-- Full migration: argus → digicap (fixed: skip non-existent tables)
SELECT dblink_connect('src', 'host=localhost port=5432 dbname=argus user=argus');
SET session_replication_role = 'replica';

-- TRUNCATE all
TRUNCATE users, organizations, system_settings, syslog_parse_patterns CASCADE;

-- 1단계: 독립 테이블

-- 2단계: assets

-- 3단계: assets 참조

-- 시계열 데이터
-- device_mac_table, discovery_logs: argus에 없음 → 건너뜀

-- 4단계: 자식 테이블

SET session_replication_role = 'origin';

-- admin 브랜딩 업데이트
UPDATE users SET email = REPLACE(email, '@argus.local', '@digicap.local'), password_hash = crypt('digicap1234!', gen_salt('bf')) WHERE username = 'admin' AND email LIKE '%@argus.local';

SELECT dblink_disconnect('src');
